import api from '../api/axiosConfig';

const seatService = {
  add: (data) => api.post('/seats', data).then(r => r.data),
  getById: (id) => api.get(`/seats/${id}`).then(r => r.data),
  getByScreen: (screenId) => api.get(`/seats/screen/${screenId}`).then(r => r.data),
};

export default seatService;
